create table tb_cliente (id bigint generated by default as identity, cpf varchar(255), email varchar(255) unique, name varchar(255), telefone varchar(255), primary key (id));
create table tb_pagamento (quantidade_parcelas integer, valor_total numeric(38,2), id bigint generated by default as identity, processo_id bigint unique, status_pagamento varchar(255) check (status_pagamento in ('PAGO','EM_ATRASO','AGUARDANDO_PAGAMENTO')), primary key (id));
create table tb_parcela (data_parcela date, valor numeric(38,2), id bigint generated by default as identity, pagamento_id bigint, status_pagamento varchar(255) check (status_pagamento in ('PAGO','EM_ATRASO','AGUARDANDO_PAGAMENTO')), primary key (id));
create table tb_processo (data date, cliente_id bigint, id bigint generated by default as identity, descricao varchar(255), numero varchar(255), situacao varchar(255), primary key (id));
create table tb_role (id bigint generated by default as identity, authority varchar(255), primary key (id));
create table tb_user (id bigint generated by default as identity, cpf varchar(255), email varchar(255) unique, name varchar(255), password varchar(255), telefone varchar(255), primary key (id));
create table tb_user_role (role_id bigint not null, user_id bigint not null, primary key (role_id, user_id));
alter table if exists tb_pagamento add constraint FK9lydvabtawxfo9sxho8ebcy80 foreign key (processo_id) references tb_processo;
alter table if exists tb_parcela add constraint FKtbxmrdibyrqxsu2sjwk15lmhe foreign key (pagamento_id) references tb_pagamento;
alter table if exists tb_processo add constraint FKqnjsc3dvaju56icr91tpxqr9v foreign key (cliente_id) references tb_cliente;
alter table if exists tb_user_role add constraint FKea2ootw6b6bb0xt3ptl28bymv foreign key (role_id) references tb_role;
alter table if exists tb_user_role add constraint FK7vn3h53d0tqdimm8cp45gc0kl foreign key (user_id) references tb_user;

